form:Form.form:Scripts:
		function FilterGrid() {
	Ctrl("grdVariables").FilterElements("","");
	if (Ctrl("buscar").GetCValue() != "") Ctrl("grdVariables").FilterElements(Ctrl("buscar").GetCValue(),"");
}

function ValidaGrilla (pobjButton) {

	var bolResult = true;
	var strMen = "";
	var objGrid = Ctrl("grdVariables");
	var x;
	var strTipo;
	var strValor;
	var objTextBox;

	//Desfiltra todo para buscar mejor
	objGrid.FilterElements("","");
	Ctrl("buscar").SetCValue("");
	var TotalRows = objGrid.TotalRowsCount(); 

    for (x = 0; x < TotalRows ; x++) {

		//Obtiene el valor
		strValor = objGrid.GetCellXValue("txtGridValor", x);

		if (strValor != "") {

			//Obtiene el tipo de valor de variable
			strTipo = objGrid.GetCellXValue("cboGridTipo", x);

			switch (strTipo) {
				case "datetime":
					bolResult = isDate(strValor);
					strMen = "Formato inválido de fechas. Se esperaba dd/mm/aaaa o dd/mm/aa.";
					break;

				case "double":
					bolResult = isDouble(strValor);
					strMen = "Formato inválido de número decimal.";
					break;

				case "bool":
					bolResult = isBoolean(strValor);
					strMen = "Formato inválido para un valor lógico.";
					break;

				case "int":
					bolResult = isInteger(strValor);
					strMen = "Formato inválido de número entero.";
					break;
			}

			//Si no está correcto le da el foco 
			if (!bolResult) {
				objGrid.GotoRow(objGrid.GetRowID(x));
				objTextBox = objGrid.GetCellSelectedControl("txtGridValor");
				objTextBox.SetFocus();
				alert(strMen);
				break;
			}
		}
    }



	return bolResult;
}
